import subprocess
import os

def convertDocument(inputfile, outputfile, targetformat):
    try :
        if not os.path.isfile(inputfile) or inputfile[-4:].lower() != '.doc':
            print('Input file is not a .docx file!')
            return None

        libreoffice = 'libreoffice --headless --convert-to {0} {1} --outdir {2}'.format(targetformat, inputfile, os.path.dirname(outputfile))
        subprocess.call([libreoffice])
        print("Converted {0} to {1}".format(inputfile, outputfile))
    except Exception as e :
            print('Error: ',e)